import{_ as t,o as i,c as o,ag as e}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"[Admin Specs] Sprint 2: Quản trị Điểm đến (POI Management)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-2-quan-tri-diem-den/06-admin-specs.md","filePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-2-quan-tri-diem-den/06-admin-specs.md"}'),a={name:"99-tham-khao/archive/02-quan-ly-sprint/sprint-2-quan-tri-diem-den/06-admin-specs.md"};function r(l,n,c,s,h,d){return i(),o("div",null,[...n[0]||(n[0]=[e('<h1 id="admin-specs-sprint-2-quan-tri-điem-đen-poi-management" tabindex="-1">[Admin Specs] Sprint 2: Quản trị Điểm đến (POI Management) <a class="header-anchor" href="#admin-specs-sprint-2-quan-tri-điem-đen-poi-management" aria-label="Permalink to &quot;[Admin Specs] Sprint 2: Quản trị Điểm đến (POI Management)&quot;">​</a></h1><p>Đặc tả chi tiết giao diện và tương tác dành cho Quản trị viên tại hệ thống <code>/admin/destinations</code>.</p><h2 id="_1-giao-dien-danh-sach-list-view" tabindex="-1">1. Giao diện Danh sách (List View) <a class="header-anchor" href="#_1-giao-dien-danh-sach-list-view" aria-label="Permalink to &quot;1. Giao diện Danh sách (List View)&quot;">​</a></h2><ul><li><strong>Component</strong>: <code>Table</code> (HeroUI).</li><li><strong>Columns</strong>: <ul><li><strong>Tên</strong>: Avatar ảnh đại diện, Tên tiếng Việt/Anh bên dưới.</li><li><strong>Vùng miền</strong>: Chip (Miền Bắc: blue, Miền Trung: orange, Miền Nam: green).</li><li><strong>Slug</strong>: Code block mini màu xám nhạt (<code>bg-slate-100</code>).</li><li><strong>Trạng thái</strong>: Switch (Active/Hidden) cập nhật trực tiếp qua API.</li><li><strong>Hành động</strong>: Tooltip (Edit, Delete).</li></ul></li><li><strong>Search Bar</strong>: Ô tìm kiếm phía trên bảng, hỗ trợ tìm theo <code>name</code> hoặc <code>slug</code>.</li><li><strong>Add New Button</strong>: Nút &quot;Thêm điểm đến mới&quot; màu primary, icon <code>Plus</code>.</li></ul><h2 id="_2-form-them-moi-chinh-sua-modal-view" tabindex="-1">2. Form Thêm mới/Chỉnh sửa (Modal View) <a class="header-anchor" href="#_2-form-them-moi-chinh-sua-modal-view" aria-label="Permalink to &quot;2. Form Thêm mới/Chỉnh sửa (Modal View)&quot;">​</a></h2><ul><li><strong>Component</strong>: <code>Modal</code> (HeroUI), kích thước <code>3xl</code>, scroll-behavior <code>inside</code>.</li><li><strong>Layout</strong>: 2 cột trên desktop, 1 cột trên mobile.</li><li><strong>Phần nhập liệu (Form Fields)</strong>: <ul><li><strong>BilingualInput</strong>: Hộp nhập song ngữ VI/EN.</li><li><strong>Slug Generator</strong>: Khi nhập <code>nameVi</code>, <code>slug</code> tự động sinh ra nhưng cho phép edit.</li><li><strong>ImageUploader</strong>: Kéo thả ảnh. Sau khi upload, hiển thị ảnh preview kèm nút xóa (x).</li><li><strong>RegionSelect</strong>: Dropdown chọn Vùng miền (3 miền cố định — <code>getRegionsAction</code> / seed DB).</li></ul></li><li><strong>Validation (Client-side)</strong>: <ul><li><code>nameVi</code> không được trống.</li><li><code>regionId</code> phải được chọn.</li><li><code>slug</code> không được chứa ký tự đặc biệt, chỉ <code>a-z</code>, <code>0-9</code>, <code>-</code>.</li></ul></li></ul><h2 id="_3-quy-trinh-tuong-tac-interaction-flows" tabindex="-1">3. Quy trình Tương tác (Interaction Flows) <a class="header-anchor" href="#_3-quy-trinh-tuong-tac-interaction-flows" aria-label="Permalink to &quot;3. Quy trình Tương tác (Interaction Flows)&quot;">​</a></h2><ul><li><strong>Thao tác Sửa</strong>: Mở Modal -&gt; Đổ dữ liệu cũ vào form -&gt; Nhấn &quot;Lưu&quot; -&gt; Gọi <code>PUT /api/v1/destinations/:id</code> -&gt; Toast thông báo thành công -&gt; Re-fetch data table.</li><li><strong>Thao tác Xóa</strong>: Click Delete -&gt; Alert confirm -&gt; Gọi <code>DELETE /api/v1/destinations/:id</code> -&gt; Nếu lỗi 403 (do có tour liên quan) -&gt; Hiển thị Modal thông báo chi tiết lỗi ràng buộc.</li><li><strong>Tối ưu UX</strong>: Hiển thị <code>Skeleton</code> khi table đang load data từ API.</li></ul><h2 id="_4-trang-cai-đat-he-thong-system-settings" tabindex="-1">4. Trang Cài đặt Hệ thống (System Settings) <a class="header-anchor" href="#_4-trang-cai-đat-he-thong-system-settings" aria-label="Permalink to &quot;4. Trang Cài đặt Hệ thống (System Settings)&quot;">​</a></h2><ul><li><strong>Đường dẫn</strong>: <code>/admin/settings/system</code> (và các module con như <code>/admin/settings/homepage</code>, <code>/admin/settings/seo</code>).</li><li><strong>Mục đích</strong>: Quản lý trạng thái vận hành và các thiết lập toàn cục của hệ thống.</li><li><strong>Giao diện</strong>: <ul><li>Sử dụng các Form component chia theo từng nhóm (General, Hero Section, Stats, SEO).</li><li>Lưu trữ dữ liệu dạng key-value vào bảng <code>SystemSetting</code> trong database.</li></ul></li><li><strong>Tính năng chính</strong>: <ul><li><strong>Cài đặt chung (General)</strong>: Quản lý logo, thông tin liên hệ, trạng thái bảo trì.</li><li><strong>Cấu hình Trang chủ (Homepage)</strong>: Thay đổi banner (Hero Section), câu khẩu hiệu, hiển thị thống kê.</li><li><strong>SEO &amp; Metadata</strong>: Cấu hình <code>siteTitle</code>, <code>metaDescription</code>, <code>favicon</code>, thẻ OpenGraph.</li></ul></li><li><strong>Lưu ý kỹ thuật</strong>: Dữ liệu cài đặt được load từ Prisma và xử lý form thông qua Next.js Server Actions.</li></ul><hr><p><em>Tài liệu đặc tả Admin cho Sprint 2 (Đã cập nhật bổ sung Cài đặt hệ thống).</em></p>',12)])])}const u=t(a,[["render",r]]);export{m as __pageData,u as default};
